import React from "react";
import MasonryGrid from "./MasonryGrid";
import Wave from "../DecorationComponents/wavecircle.svg";



const Galeria = () => {
  return (
    <section className="pointer-events-none absolute inset-0 z-0 overflow-hidden">

      <div className="pointer-events-none absolute inset-0 z-0 overflow-hidden flex items-center justify-end">
        <img
          src={Wave}
          className="w-[120vw] -mr-[50vw] animate-spin-slow"
          style={{ top: '20%', right: '-35vw', transformOrigin: 'center center' }}
        />
      </div>

      <div className="pointer-events-none absolute inset-0 z-0 overflow-hidden flex items-center justify-end">
        <img
          src={Wave}
          className="w-[120vw] -ml-[50vw] animate-spin-slow"
          style={{ top: '20%', right: '-35vw', transformOrigin: 'center center' }}
        />
      </div>

      {/* CONTENIDO */}
      <div className="relative z-10 text-center mb-[3vh">
        <h1 className="titulo-playfair font-semibold text-[#7D6239] text-[2rem]">
          ¿Te quedaste con ganas de ver más?
        </h1>
        <div className="h-[5px] w-[3rem] mx-auto rounded-full bg-gradient-to-r from-[#CC2329] to-[#F55809]" />
      </div>

      <div className=" relative z-10 w-[50%] mx-auto ">
        <MasonryGrid />
      </div>

    </section>
  );
};

export default Galeria;
